import type { CareerQuestion } from "./rrt-questions";

export const cardiacSonographerQuestionsBatch3: CareerQuestion[] = [
  { id: "cardecho-070", stem: "In the parasternal long-axis (PLAX) view, which structure is located most anteriorly?", options: ["Right ventricle", "Left ventricle", "Left atrium", "Aortic root"], correctIndex: 0, rationale: "In PLAX, the RV is the most anterior structure, closest to the transducer. Behind it lies the interventricular septum, then the LV cavity, mitral valve, and LA posteriorly.", difficulty: 1, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-071", stem: "The apical two-chamber (A2C) view displays which cardiac structures?", options: ["Left atrium and left ventricle with anterior and inferior walls", "All four cardiac chambers", "Right atrium and right ventricle", "Aortic root and LVOT"], correctIndex: 0, rationale: "The A2C view shows only the LA and LV, displaying the anterior and inferior LV walls. It does not include any right-sided structures or the interventricular septum.", difficulty: 1, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-072", stem: "The suprasternal notch view is primarily used to assess:", options: ["Aortic arch, its branches, and descending aorta", "Mitral valve anatomy", "Left ventricular function", "Tricuspid regurgitation"], correctIndex: 0, rationale: "The suprasternal notch view provides visualization of the aortic arch, innominate artery, left carotid, left subclavian arteries, and proximal descending aorta. It is useful for coarctation assessment.", difficulty: 1, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-073", stem: "Which parasternal short-axis level best visualizes the papillary muscles?", options: ["Mid-ventricular level", "Aortic valve level", "Mitral valve level", "Apical level"], correctIndex: 0, rationale: "The mid-ventricular PSAX view shows the posteromedial and anterolateral papillary muscles as two echogenic structures within the LV cavity, used for assessing regional wall motion.", difficulty: 1, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-074", stem: "In the apical five-chamber (A5C) view, the fifth chamber refers to:", options: ["The LVOT and aortic valve", "The coronary sinus", "The pulmonary artery", "The superior vena cava"], correctIndex: 0, rationale: "The A5C view is derived from the A4C by angling the transducer anteriorly to include the LVOT and aortic valve, creating the appearance of a 'fifth chamber.'", difficulty: 1, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-075", stem: "The right ventricular inflow view is obtained from which transducer position?", options: ["Parasternal position with medial angulation toward the right hip", "Apical position", "Suprasternal notch", "Subcostal position only"], correctIndex: 0, rationale: "The RV inflow view is obtained from the parasternal window by tilting the transducer medially and inferiorly. It shows the RA, tricuspid valve, and RV, useful for assessing TV pathology.", difficulty: 2, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-076", stem: "What is the normal M-mode measurement for interventricular septal thickness in diastole?", options: ["6-11 mm", "15-20 mm", "2-4 mm", "20-25 mm"], correctIndex: 0, rationale: "Normal IVSd (interventricular septal thickness in diastole) is 6-11 mm. Values >11 mm suggest LV hypertrophy. M-mode provides accurate measurements due to high temporal resolution.", difficulty: 1, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-077", stem: "Normal left ventricular internal dimension in diastole (LVIDd) by M-mode is:", options: ["3.5-5.7 cm", "1.0-2.0 cm", "6.5-8.0 cm", "8.0-10.0 cm"], correctIndex: 0, rationale: "Normal LVIDd is 3.5-5.7 cm (may vary by body surface area). LVIDd >5.7 cm indicates LV dilation. LVIDs normal range is 2.0-4.0 cm.", difficulty: 1, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-078", stem: "The E-point septal separation (EPSS) on M-mode of the mitral valve correlates with:", options: ["Left ventricular ejection fraction", "Mitral valve area", "Right ventricular function", "Aortic valve gradient"], correctIndex: 0, rationale: "EPSS measures the distance between the E-point of the anterior mitral leaflet and the interventricular septum. EPSS >10 mm suggests reduced LVEF. Normal EPSS is <6-7 mm.", difficulty: 2, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-079", stem: "On M-mode of the aortic valve, normal aortic root dimension at the sinuses of Valsalva is:", options: ["2.0-3.7 cm", "5.0-6.0 cm", "0.5-1.0 cm", "7.0-8.0 cm"], correctIndex: 0, rationale: "Normal aortic root at the sinuses of Valsalva is 2.0-3.7 cm. Measurement >4.0 cm suggests aortic root dilation. Indexed values account for body surface area.", difficulty: 2, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-080", stem: "Fractional shortening (FS) by M-mode is calculated as:", options: ["(LVIDd - LVIDs) / LVIDd × 100%", "LVIDs / LVIDd × 100%", "LVEF / heart rate", "Stroke volume / EDV"], correctIndex: 0, rationale: "FS = (LVIDd - LVIDs) / LVIDd × 100%. Normal FS is 25-45%. FS correlates with LVEF but assumes uniform wall motion, making it less accurate in regional dysfunction.", difficulty: 2, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-081", stem: "M-mode of the mitral valve in mitral stenosis shows:", options: ["Decreased E-F slope and anterior motion of the posterior leaflet parallel to the anterior leaflet", "Increased E-F slope", "Systolic anterior motion", "Normal opening pattern"], correctIndex: 0, rationale: "In MS, the restricted posterior leaflet moves anteriorly during diastole (parallel to the anterior leaflet instead of the normal posterior motion), and the E-F slope is reduced due to impaired early diastolic filling.", difficulty: 3, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-082", stem: "What normal LV posterior wall thickness in diastole indicates hypertrophy?", options: [">11 mm", ">5 mm", ">3 mm", ">25 mm"], correctIndex: 0, rationale: "Normal LV posterior wall thickness in diastole (LVPWd) is 6-11 mm. Values >11 mm indicate LV hypertrophy, which may result from hypertension, aortic stenosis, or hypertrophic cardiomyopathy.", difficulty: 1, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-083", stem: "Tissue characterization by echocardiography refers to:", options: ["Assessment of myocardial echo texture and reflectivity to identify infiltrative or fibrotic processes", "Measuring blood flow velocities through valves", "Calculating chamber volumes", "Assessing valve leaflet mobility"], correctIndex: 0, rationale: "Tissue characterization evaluates myocardial reflectivity and echo texture. Increased brightness suggests fibrosis or infiltration (amyloidosis shows granular sparkling). Decreased reflectivity may indicate edema.", difficulty: 3, category: "Adult Echocardiography", topic: "Tissue Characterization" },
  { id: "cardecho-084", stem: "The 'granular sparkling' myocardial appearance on echocardiography is characteristic of:", options: ["Cardiac amyloidosis", "Dilated cardiomyopathy", "Normal myocardium", "Pericardial effusion"], correctIndex: 0, rationale: "Cardiac amyloidosis produces a characteristic granular sparkling or ground-glass appearance of the myocardium due to amyloid protein infiltration, often with biatrial enlargement and thickened valves.", difficulty: 2, category: "Adult Echocardiography", topic: "Tissue Characterization" },
  { id: "cardecho-085", stem: "Myocardial integrated backscatter analysis can differentiate:", options: ["Normal myocardium from fibrotic or scarred tissue based on acoustic properties", "Arterial from venous flow", "Systolic from diastolic time intervals", "Left from right ventricular volumes"], correctIndex: 0, rationale: "Integrated backscatter measures the average acoustic energy reflected from myocardium, distinguishing normal tissue from fibrosis, scar, or infiltration based on differential reflectivity patterns.", difficulty: 4, category: "Adult Echocardiography", topic: "Tissue Characterization" },
  { id: "cardecho-086", stem: "Speckle tracking echocardiography (STE) measures:", options: ["Myocardial deformation (strain) by tracking acoustic markers frame-to-frame", "Transvalvular pressure gradients", "Blood pool velocity only", "Pericardial thickness"], correctIndex: 0, rationale: "STE tracks natural acoustic markers (speckles) in the myocardium throughout the cardiac cycle to calculate strain (deformation) and strain rate, providing angle-independent assessment of myocardial mechanics.", difficulty: 3, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-087", stem: "Normal global longitudinal strain (GLS) of the left ventricle is approximately:", options: ["-18% to -22% (more negative = better function)", "-5% to -8%", "0% to +5%", "+15% to +25%"], correctIndex: 0, rationale: "Normal GLS is approximately -18% to -22%. GLS is negative because the myocardium shortens in systole. Values less negative than -16% suggest impaired systolic function even with preserved LVEF.", difficulty: 3, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-088", stem: "In a patient receiving cardiotoxic chemotherapy, subclinical LV dysfunction is detected earliest by:", options: ["Global longitudinal strain reduction before LVEF decline", "LVEF change", "E/A ratio reversal", "Increased LV wall thickness"], correctIndex: 0, rationale: "GLS detects subclinical myocardial dysfunction before LVEF drops. A relative GLS decrease >15% from baseline during chemotherapy suggests cardiotoxicity and may prompt cardioprotective therapy.", difficulty: 3, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-089", stem: "The 'bull's-eye' plot in speckle tracking displays:", options: ["Regional longitudinal strain values mapped across 16 or 17 LV segments", "Color Doppler flow patterns", "M-mode measurements", "3D volumetric data"], correctIndex: 0, rationale: "The bull's-eye (polar map) displays GLS values for each LV segment from the apical views. Red indicates reduced strain; blue/purple indicates normal strain. Patterns can suggest specific etiologies (e.g., apical sparing in amyloidosis).", difficulty: 3, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-090", stem: "Apical sparing pattern on the strain bull's-eye map is characteristic of:", options: ["Cardiac amyloidosis", "Ischemic cardiomyopathy", "Takotsubo cardiomyopathy", "Hypertensive heart disease"], correctIndex: 0, rationale: "Cardiac amyloidosis shows reduced strain in basal and mid segments with relative apical sparing, creating a cherry-on-top pattern. This pattern has high specificity for amyloid infiltration.", difficulty: 4, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-091", stem: "Right ventricular longitudinal strain is typically measured from:", options: ["The RV free wall in the apical 4-chamber view", "The parasternal short-axis view", "The suprasternal view", "The subcostal sagittal view"], correctIndex: 0, rationale: "RV free wall longitudinal strain is measured from the A4C view, focusing on the three RV free wall segments. Normal RV free wall strain is approximately -25% to -30%. Values less negative suggest RV dysfunction.", difficulty: 3, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-092", stem: "Circumferential and radial strain assess:", options: ["LV shortening and thickening in the short-axis plane, respectively", "Longitudinal shortening only", "Valve opening motion", "Aortic wall compliance"], correctIndex: 0, rationale: "Circumferential strain measures myocardial shortening along the circumference (negative in systole), while radial strain measures wall thickening (positive in systole). Both are assessed from PSAX views.", difficulty: 4, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-093", stem: "Mechanical dyssynchrony by speckle tracking is identified by:", options: ["Time-to-peak strain differences between opposing LV segments exceeding a threshold", "Uniform strain timing across all segments", "Normal QRS duration on ECG", "Equal E and A wave velocities"], correctIndex: 0, rationale: "Mechanical dyssynchrony is detected when there is significant delay in time-to-peak strain between LV segments (>130 ms between opposing walls). This may guide cardiac resynchronization therapy decisions.", difficulty: 4, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-094", stem: "3D echocardiography provides more accurate LV volume measurements than 2D because:", options: ["It avoids geometric assumptions and foreshortening errors inherent in 2D methods", "It has higher temporal resolution", "It uses Doppler for volume calculation", "It requires fewer imaging windows"], correctIndex: 0, rationale: "3D echo directly measures LV volumes without geometric modeling assumptions. 2D Simpson's method assumes elliptical geometry and is affected by apical foreshortening, leading to volume underestimation.", difficulty: 2, category: "Adult Echocardiography", topic: "3D Echocardiography" },
  { id: "cardecho-095", stem: "Real-time 3D echocardiography of the mitral valve is particularly useful for:", options: ["Surgical planning by providing en-face views of mitral valve anatomy and pathology", "Measuring TR velocity", "Calculating cardiac output", "Assessing aortic root dimensions"], correctIndex: 0, rationale: "3D echo provides the 'surgeon's view' of the mitral valve from the LA perspective, showing scallop anatomy (A1-A3, P1-P3), commissures, and prolapse/flail segments to guide surgical repair.", difficulty: 3, category: "Adult Echocardiography", topic: "3D Echocardiography" },
  { id: "cardecho-096", stem: "A limitation of 3D echocardiography compared to 2D is:", options: ["Lower temporal resolution (frame rate) requiring ECG-gated acquisition for full volumes", "Inability to visualize cardiac structures", "Higher cost of transducers only", "Inability to measure volumes"], correctIndex: 0, rationale: "3D echo has lower frame rates than 2D imaging. Full-volume datasets often require multi-beat ECG-gated acquisition (stitching), which can introduce artifacts in patients with arrhythmias.", difficulty: 3, category: "Adult Echocardiography", topic: "3D Echocardiography" },
  { id: "cardecho-097", stem: "3D color Doppler is used to:", options: ["Visualize regurgitant jets in three dimensions and measure vena contracta area", "Replace all 2D Doppler measurements", "Measure myocardial strain", "Assess pericardial thickness"], correctIndex: 0, rationale: "3D color Doppler provides volumetric assessment of regurgitant jets. The vena contracta area (VCA) measured by 3D is more accurate than 2D vena contracta width, especially for eccentric or non-circular orifices.", difficulty: 3, category: "Adult Echocardiography", topic: "3D Echocardiography" },
  { id: "cardecho-098", stem: "Contrast echocardiography uses microbubbles primarily to:", options: ["Enhance endocardial border definition and assess myocardial perfusion", "Replace Doppler measurements", "Measure wall thickness", "Assess valve calcification"], correctIndex: 0, rationale: "Contrast agents (microbubbles) opacify the LV cavity for improved endocardial border visualization and can assess myocardial perfusion by tracking microbubble replenishment after flash destruction.", difficulty: 2, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-099", stem: "Which ultrasound contrast agents are approved for LV opacification?", options: ["Definity (perflutren) and Lumason (sulfur hexafluoride)", "Gadolinium and iodinated contrast", "Saline only", "Air bubbles from manual agitation"], correctIndex: 0, rationale: "Definity and Lumason are FDA-approved ultrasound contrast agents containing perfluorocarbon or sulfur hexafluoride gas microbubbles stabilized by lipid or polymer shells. Agitated saline is used only for right-to-left shunt detection.", difficulty: 2, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-100", stem: "Agitated saline contrast ('bubble study') crossing from the right atrium to the left atrium within 3-5 cardiac cycles indicates:", options: ["Intracardiac shunt such as patent foramen ovale or atrial septal defect", "Normal finding", "Intrapulmonary shunt", "Left-to-right shunt only"], correctIndex: 0, rationale: "Bubbles appearing in the LA within 3-5 beats of RA opacification indicate an intracardiac shunt (PFO or ASD). Delayed appearance (>5 beats) suggests intrapulmonary shunting (e.g., pulmonary AVM).", difficulty: 2, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-101", stem: "Myocardial contrast perfusion imaging identifies:", options: ["Regions of reduced or absent microvascular perfusion indicating ischemia or infarction", "Valve calcification extent", "Pericardial fluid volume", "Chamber dimensions"], correctIndex: 0, rationale: "Myocardial contrast perfusion uses microbubble destruction and replenishment kinetics to assess myocardial blood flow. Perfusion defects at rest suggest infarction; defects only with stress suggest ischemia.", difficulty: 3, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-102", stem: "A contraindication to ultrasound contrast agents includes:", options: ["Known hypersensitivity to perflutren or right-to-left, bidirectional, or transient right-to-left shunts (for some agents)", "Mild renal insufficiency", "Prior echocardiography", "History of hypertension"], correctIndex: 0, rationale: "Contraindications include hypersensitivity to the agent, and for certain agents, right-to-left shunts. Black box warnings were largely removed, but allergic reactions remain a concern. Contrast is generally very safe.", difficulty: 3, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-103", stem: "During exercise stress echocardiography, images are obtained:", options: ["At rest and immediately post-exercise (within 60-90 seconds of peak exercise)", "Only at rest", "Only during peak exercise", "30 minutes after exercise"], correctIndex: 0, rationale: "Exercise stress echo captures baseline images at rest, then post-exercise images within 60-90 seconds of stopping (treadmill) or at peak (bicycle). Wall motion is compared side-by-side.", difficulty: 2, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-104", stem: "Dobutamine stress echo protocol typically uses dobutamine doses of:", options: ["5, 10, 20, 30, and 40 mcg/kg/min with atropine if target HR not reached", "A single dose of 100 mcg/kg/min", "Only 5 mcg/kg/min", "50-80 mcg/kg/min starting dose"], correctIndex: 0, rationale: "Standard DSE protocol: 3-minute stages at 5, 10, 20, 30, 40 mcg/kg/min. Atropine (0.25-1.0 mg) added if target HR (85% age-predicted maximum) is not achieved. Low dose assesses viability.", difficulty: 3, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-105", stem: "A new regional wall motion abnormality during stress echo indicates:", options: ["Inducible myocardial ischemia in the corresponding coronary territory", "Normal stress response", "Valvular disease", "Pericardial constriction"], correctIndex: 0, rationale: "New or worsening wall motion abnormalities (WMA) during stress indicate ischemia. Fixed WMAs (present at rest and stress) suggest prior infarction/scar. Improved WMA at low dose suggests viability.", difficulty: 2, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-106", stem: "Biphasic response during low-dose dobutamine stress echo indicates:", options: ["Viable but ischemic myocardium that improves at low dose but worsens at high dose", "Infarcted non-viable myocardium", "Normal myocardium", "Artifact"], correctIndex: 0, rationale: "Biphasic response: WMA improves at low-dose dobutamine (viability) but worsens at higher doses (ischemia). This pattern predicts functional recovery after revascularization.", difficulty: 4, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-107", stem: "Indications to stop a dobutamine stress echo include:", options: ["New severe wall motion abnormality, significant arrhythmia, hypotension, or severe symptoms", "Achievement of target heart rate only", "Completion of the first stage", "Patient anxiety alone"], correctIndex: 0, rationale: "Stop criteria: new or worsening WMA in ≥2 segments, ST elevation/depression, sustained VT, symptomatic hypotension (<80 mmHg systolic drop), severe angina, or achievement of target HR.", difficulty: 3, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-108", stem: "The 16-segment or 17-segment model of the left ventricle is used in stress echo to:", options: ["Standardize reporting of regional wall motion and correlate segments with coronary territories", "Calculate valve areas", "Measure Doppler velocities", "Assess pericardial disease"], correctIndex: 0, rationale: "The ASE 17-segment model divides the LV into basal, mid, and apical segments correlated to LAD, LCx, and RCA territories. Each segment is scored: 1=normal, 2=hypokinetic, 3=akinetic, 4=dyskinetic.", difficulty: 2, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-109", stem: "Wall motion score index (WMSI) is calculated by:", options: ["Sum of individual segment scores divided by the number of segments visualized", "Peak velocity times the number of abnormal segments", "LVEF divided by heart rate", "Stroke volume multiplied by segment number"], correctIndex: 0, rationale: "WMSI = sum of segment scores / number of scored segments. Normal WMSI = 1.0. Higher values indicate more extensive WMA. WMSI >1.7 is associated with worse prognosis.", difficulty: 3, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-110", stem: "TEE is preferred over TTE for evaluation of:", options: ["Left atrial appendage thrombus, prosthetic valve endocarditis, and aortic dissection", "Routine LV function assessment", "Pericardial effusion size", "Standard Doppler measurements"], correctIndex: 0, rationale: "TEE provides superior resolution for posterior structures (LA/LAA, mitral valve, aorta). Indications include LA appendage thrombus before cardioversion, endocarditis, prosthetic valve assessment, and aortic dissection.", difficulty: 1, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-111", stem: "The mid-esophageal four-chamber view on TEE is obtained at approximately:", options: ["0 degrees with retroflexion of the probe", "90 degrees", "135 degrees", "180 degrees"], correctIndex: 0, rationale: "The ME four-chamber view is obtained at 0° multiplane angle with slight retroflexion. It shows all four chambers, both AV valves, and the interatrial septum.", difficulty: 2, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-112", stem: "The mid-esophageal bicaval view on TEE is obtained at approximately:", options: ["90-110 degrees showing SVC, IVC, RA, and interatrial septum", "0 degrees", "180 degrees", "45 degrees"], correctIndex: 0, rationale: "The ME bicaval view at 90-110° displays the SVC (right), IVC (left), RA, and interatrial septum. This is the best TEE view for assessing ASD, PFO, and IAS anatomy.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-113", stem: "The transgastric mid short-axis view on TEE is obtained by:", options: ["Advancing the probe into the stomach and anteflexing at 0 degrees", "Withdrawing to the upper esophagus at 90 degrees", "Retroflexing in the mid-esophagus at 135 degrees", "Rotating clockwise at the aortic valve level"], correctIndex: 0, rationale: "The transgastric mid SAX view is obtained with the probe in the stomach, anteflexed at 0°. It provides a short-axis view of the LV at the papillary muscle level for regional wall motion assessment.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-114", stem: "The left atrial appendage is best visualized on TEE at:", options: ["Mid-esophageal level between 0 and 90 degrees, often best at 45-60 degrees", "Transgastric level at 0 degrees", "Deep transgastric view at 120 degrees", "Upper esophageal level at 180 degrees"], correctIndex: 0, rationale: "The LAA is best seen at the ME level with multiplane rotation from 0° to 90°, often optimized at 45-60°. Multiple angles are needed to exclude thrombus, as the LAA has complex lobed anatomy.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-115", stem: "Before performing TEE, the sonographer must ensure:", options: ["The patient has fasted for at least 4-6 hours and has no esophageal pathology contraindicating the procedure", "The patient ate a full meal", "No IV access is needed", "No informed consent is required"], correctIndex: 0, rationale: "TEE preparation: 4-6 hour fasting, informed consent, IV access, assessment for esophageal stricture/varices/tumor/recent surgery. Topical anesthesia and sedation are typically administered.", difficulty: 1, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-116", stem: "Contraindications to TEE include:", options: ["Esophageal stricture, perforation, active upper GI bleeding, and recent esophageal surgery", "History of echocardiography", "Left ventricular hypertrophy", "Mild mitral regurgitation"], correctIndex: 0, rationale: "Absolute contraindications: esophageal obstruction/stricture, perforation, active GI bleeding, recent esophageal/gastric surgery. Relative: esophageal varices, cervical spine instability, coagulopathy.", difficulty: 2, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-117", stem: "The mid-esophageal aortic valve short-axis view on TEE displays:", options: ["All three aortic cusps en face with surrounding structures including the interatrial septum and tricuspid valve", "Only the mitral valve", "Left ventricular apex", "Descending aorta only"], correctIndex: 0, rationale: "The ME AV SAX view at 30-60° shows all three aortic cusps (NCC posteriorly, RCC anteriorly, LCC to the left), the interatrial septum, LA, RA, RVOT, and TV.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-118", stem: "The mid-esophageal aortic valve long-axis view at 120-135 degrees shows:", options: ["LVOT, aortic valve in long axis, proximal ascending aorta, and right pulmonary artery", "Only the mitral valve", "Tricuspid valve and RA", "Descending thoracic aorta cross-section"], correctIndex: 0, rationale: "The ME AV LAX at 120-135° displays the LVOT, aortic valve (NCC and RCC), sinuses of Valsalva, sinotubular junction, proximal ascending aorta, and often the RPA behind the aorta.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-119", stem: "Intraoperative TEE is used during cardiac surgery primarily to:", options: ["Assess surgical repair results, guide cannulation, detect air or complications in real time", "Replace preoperative imaging entirely", "Monitor blood pressure", "Assess skin incision quality"], correctIndex: 0, rationale: "Intraoperative TEE: pre-bypass assessment confirms pathology, guides cannulation, detects intracardiac air after cardiopulmonary bypass, and immediately evaluates repair adequacy (e.g., residual MR after mitral repair).", difficulty: 2, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-120", stem: "On 2D echo, myocardial segments are described using the wall motion grading scale. Akinesis means:", options: ["Absent wall motion and thickening", "Normal wall motion", "Reduced wall motion", "Outward bulging during systole"], correctIndex: 0, rationale: "Wall motion scoring: 1=normokinesis (normal), 2=hypokinesis (reduced), 3=akinesis (absent motion/thickening), 4=dyskinesis (paradoxical outward motion), 5=aneurysmal.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-121", stem: "Dyskinesis of the LV apex following anterior STEMI refers to:", options: ["Paradoxical outward motion (bulging) of the apex during systole", "Normal contraction of the apex", "Increased thickening of the apex", "Absent apical wall"], correctIndex: 0, rationale: "Dyskinesis describes paradoxical systolic expansion (outward bulging) of a segment during systole instead of normal inward contraction. It indicates transmural scar from myocardial infarction.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-122", stem: "The 'comet-tail' artifact in 2D echocardiography is associated with:", options: ["Highly reflective structures such as mechanical prosthetic valve components or calcification", "Normal soft tissue", "Pericardial fluid", "Blood flow through a stenotic valve"], correctIndex: 0, rationale: "Comet-tail (reverberation) artifacts arise from closely spaced, highly reflective interfaces. They are commonly seen behind mechanical valve occluders, calcified structures, and intracardiac devices.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-123", stem: "Foreshortening of the LV apex in 2D imaging results in:", options: ["Underestimation of LV length and volumes", "Overestimation of LV volumes", "More accurate EF measurements", "Better visualization of the apex"], correctIndex: 0, rationale: "Foreshortening occurs when the imaging plane cuts obliquely through the LV, missing the true apex. This leads to underestimation of LV length, volumes, and can mask apical pathology (thrombus, WMA).", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-124", stem: "Harmonic imaging improves image quality by:", options: ["Using the second harmonic frequency generated within tissue to reduce near-field artifact and clutter", "Doubling the transducer frequency", "Eliminating all artifacts", "Using lower frequency transducers"], correctIndex: 0, rationale: "Tissue harmonic imaging transmits at a fundamental frequency and receives at the second harmonic. This reduces near-field clutter, side lobes, and reverberation, improving endocardial definition.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-125", stem: "The lateral resolution of a 2D echo image depends on:", options: ["Beam width, which is narrowest at the focal zone", "Pulse repetition frequency", "Doppler sample volume size", "Patient heart rate"], correctIndex: 0, rationale: "Lateral resolution equals beam width. It is best at the focal zone where the beam is narrowest. Lateral resolution is always worse than axial resolution. Multiple focal zones improve resolution but decrease frame rate.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-126", stem: "Axial resolution in echocardiography is determined by:", options: ["Spatial pulse length, which depends on frequency and number of cycles per pulse", "Beam width at the focal zone", "Frame rate", "Transducer footprint size"], correctIndex: 0, rationale: "Axial resolution = spatial pulse length / 2. Higher frequency and fewer cycles per pulse shorten the spatial pulse length, improving axial resolution. Axial resolution is the best resolution in ultrasound.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-127", stem: "A high frame rate in 2D echocardiography is important for:", options: ["Visualizing rapidly moving structures such as valve leaflets and detecting wall motion abnormalities", "Improving lateral resolution", "Increasing penetration depth", "Reducing artifact"], correctIndex: 0, rationale: "Higher frame rates improve temporal resolution, critical for assessing rapidly moving structures (valves, endocardium) and detecting subtle WMAs. Trade-offs include reduced line density and lateral resolution.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-128", stem: "Sector width in 2D imaging affects frame rate because:", options: ["A wider sector requires more scan lines per frame, reducing frame rate", "A wider sector uses less processing power", "A narrower sector always produces worse images", "Sector width has no effect on frame rate"], correctIndex: 0, rationale: "Frame rate = PRF / (lines per frame). Wider sectors require more scan lines, decreasing frame rate. Narrowing the sector increases frame rate and temporal resolution, helpful for fast-moving structures.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-129", stem: "During a stress echo, the apical 4-chamber view assesses wall motion in which coronary territories?", options: ["LAD (septum, apex), LCx (lateral wall), and RCA (inferior septum)", "Only the LAD territory", "Only the RCA territory", "Pulmonary artery territories"], correctIndex: 0, rationale: "A4C shows: septum (LAD), lateral wall (LCx), apex (LAD), and basal inferior septum (RCA). Each wall segment is assigned to a coronary territory per the ASE 17-segment model.", difficulty: 3, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-130", stem: "The deep transgastric view on TEE is used to obtain:", options: ["CW Doppler aligned parallel to flow through the aortic valve and LVOT", "Mitral valve en-face images", "Left atrial appendage views", "Descending aorta cross-sections"], correctIndex: 0, rationale: "The deep transgastric (TG) view provides near-parallel alignment with LVOT and aortic valve flow, enabling accurate CW Doppler measurement of aortic valve gradients during intraoperative TEE.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-131", stem: "Which TEE view best evaluates the descending thoracic aorta?", options: ["Short-axis and long-axis views obtained by rotating the probe posteriorly at 0 and 90 degrees", "Mid-esophageal four-chamber view", "Transgastric short-axis view", "Deep transgastric view"], correctIndex: 0, rationale: "The descending thoracic aorta is seen by rotating the probe posteriorly from the esophagus. Cross-section at 0° and longitudinal at 90°. Used for aortic dissection, atheroma, and aneurysm assessment.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-132", stem: "The upper esophageal aortic arch view on TEE shows:", options: ["Aortic arch in long axis with origins of great vessels", "Mitral valve anatomy", "Left ventricular apex", "Coronary sinus"], correctIndex: 0, rationale: "The UE aortic arch view at 0° shows the aortic arch in long axis. Rotating to 90° may show great vessel origins. This view is important for assessing arch pathology and atheroma.", difficulty: 3, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-133", stem: "M-mode through the aortic valve shows a 'box-like' opening pattern in:", options: ["Normal aortic valve function", "Severe aortic stenosis", "Aortic regurgitation", "Mitral stenosis"], correctIndex: 0, rationale: "Normal AV M-mode shows a box-like or parallelogram opening pattern during systole. In AS, the opening is reduced. Eccentric closure line suggests a bicuspid valve.", difficulty: 2, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-134", stem: "The M-mode finding of 'B-bump' on the mitral valve tracing indicates:", options: ["Elevated left ventricular end-diastolic pressure", "Normal diastolic function", "Mitral stenosis", "Mitral regurgitation"], correctIndex: 0, rationale: "The B-bump (or AC shoulder) on mitral valve M-mode represents premature partial closure of the mitral valve before systole, indicating elevated LVEDP. It may be seen in acute aortic regurgitation.", difficulty: 4, category: "Adult Echocardiography", topic: "M-Mode Measurements" },
  { id: "cardecho-135", stem: "In 2D echo, the normal mitral valve opens to form a:", options: ["Fish-mouth or hockey-stick pattern with the anterior leaflet being longer than the posterior", "Circular opening", "Triangular opening", "Square opening"], correctIndex: 0, rationale: "Normal MV opening in 2D: the anterior leaflet (longer, more mobile) opens widely, creating a fish-mouth or hockey-stick appearance. The posterior leaflet is shorter and has limited excursion.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-136", stem: "The subcostal IVC view assesses IVC size and respiratory variation to estimate:", options: ["Right atrial pressure", "Left atrial pressure", "Aortic valve gradient", "Mitral valve area"], correctIndex: 0, rationale: "IVC diameter and inspiratory collapse from the subcostal view estimate RAP. Normal IVC <2.1 cm with >50% collapse = RAP 0-5 mmHg; >2.1 cm with <50% collapse = RAP 10-20 mmHg.", difficulty: 1, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-137", stem: "The subcostal four-chamber view is the preferred approach for assessing:", options: ["The interatrial septum for ASD and the pericardium for effusion", "Aortic valve morphology only", "LVOT diameter only", "Pulmonary veins only"], correctIndex: 0, rationale: "Subcostal 4-chamber: ultrasound beam is perpendicular to the IAS, making it the best TTE view for detecting ASD. Also excellent for pericardial effusion (pericardium appears as a bright line).", difficulty: 2, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-138", stem: "Strain rate imaging differs from strain in that it measures:", options: ["The rate of myocardial deformation per unit time rather than the total deformation", "Total shortening of the myocardium", "Blood flow velocity", "Valve gradient"], correctIndex: 0, rationale: "Strain measures total myocardial deformation (% change in length), while strain rate measures the speed of deformation (1/s). Strain rate is less load-dependent and may better reflect intrinsic contractility.", difficulty: 4, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-139", stem: "Post-systolic shortening (PSS) detected by strain imaging indicates:", options: ["Myocardial ischemia or scar, as deformation continues after aortic valve closure", "Normal myocardial mechanics", "Enhanced contractility", "Valve disease"], correctIndex: 0, rationale: "Post-systolic shortening is myocardial deformation occurring after AVC. It is a marker of ischemia or scar, as injured segments cannot contract normally during systole and shorten passively afterward.", difficulty: 4, category: "Adult Echocardiography", topic: "Strain Imaging" },
  { id: "cardecho-140", stem: "In 3D echo, multiplanar reconstruction (MPR) allows:", options: ["Simultaneous display of orthogonal 2D planes derived from the 3D dataset", "Only volumetric rendering", "Doppler velocity measurements", "M-mode tracings"], correctIndex: 0, rationale: "MPR from a 3D dataset displays coronal, sagittal, and transverse planes simultaneously. The operator can navigate through the dataset to optimize views of structures from any angle.", difficulty: 3, category: "Adult Echocardiography", topic: "3D Echocardiography" },
  { id: "cardecho-141", stem: "3D echo is particularly useful for measuring:", options: ["Aortic and mitral annular geometry, which is often non-circular", "Only LV mass", "Heart rate", "Blood pressure"], correctIndex: 0, rationale: "3D echo reveals that the aortic annulus is elliptical (not circular), which is critical for TAVR sizing. The mitral annulus is also saddle-shaped, better characterized by 3D than 2D.", difficulty: 3, category: "Adult Echocardiography", topic: "3D Echocardiography" },
  { id: "cardecho-142", stem: "Contrast echo showing an LV apical thrombus that was not visible on standard 2D demonstrates:", options: ["The superior sensitivity of contrast for detecting LV thrombus compared to unenhanced imaging", "That the thrombus does not exist", "Normal apical variant", "Artifact"], correctIndex: 0, rationale: "Contrast significantly improves LV thrombus detection sensitivity (from ~33% to >95%). The contrast-enhanced cavity opacification delineates thrombus from adjacent myocardium, especially at the apex.", difficulty: 3, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-143", stem: "The mechanical index (MI) setting during contrast echocardiography should be:", options: ["Low (MI <0.3) to prevent premature destruction of microbubbles", "High (MI >1.5) for maximum contrast", "Irrelevant to contrast imaging", "Set to maximum at all times"], correctIndex: 0, rationale: "Low MI prevents microbubble destruction, allowing real-time continuous imaging. High MI causes rapid destruction (flash), used in perfusion imaging to assess replenishment kinetics.", difficulty: 3, category: "Adult Echocardiography", topic: "Contrast Echocardiography" },
  { id: "cardecho-144", stem: "Vasodilator stress agents used with echo include:", options: ["Dipyridamole and regadenoson, which cause coronary vasodilation and flow heterogeneity", "Dobutamine only", "Epinephrine only", "Norepinephrine only"], correctIndex: 0, rationale: "Vasodilator agents (dipyridamole, adenosine, regadenoson) cause coronary vasodilation. Stenotic vessels cannot dilate further, creating flow disparity. They are mainly used with perfusion imaging or for patients who cannot exercise.", difficulty: 3, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-145", stem: "In stress echo, the sensitivity for detecting coronary artery disease is highest with:", options: ["Exercise or dobutamine stress combined with 2D wall motion analysis", "Resting images alone", "M-mode only", "Color Doppler only"], correctIndex: 0, rationale: "Stress echo sensitivity for CAD detection is 80-85% with exercise or dobutamine. Specificity is 80-88%. Sensitivity increases with multi-vessel disease and is lower for single-vessel disease.", difficulty: 2, category: "Adult Echocardiography", topic: "Stress Echocardiography" },
  { id: "cardecho-146", stem: "During 2D imaging, the gain setting should be adjusted to:", options: ["Optimize tissue-blood pool contrast while visualizing endocardial borders without excess noise", "Maximum at all times", "Minimum for all patients", "Only changed after the exam"], correctIndex: 0, rationale: "Optimal gain provides clear tissue-blood pool interface. Too much gain causes noise and obscures borders. Too little gain causes dropout of endocardial definition. Adjust for each view.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-147", stem: "The time-gain compensation (TGC) controls in echocardiography compensate for:", options: ["Attenuation of the ultrasound beam with increasing depth", "Lateral beam spreading", "Doppler aliasing", "Refraction artifacts"], correctIndex: 0, rationale: "TGC applies progressively more gain to deeper signals to compensate for tissue attenuation. The operator adjusts TGC sliders to produce uniform brightness across all depths.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-148", stem: "The Nyquist limit in pulsed-wave Doppler equals:", options: ["Half the pulse repetition frequency (PRF)", "Twice the PRF", "The transmitted frequency", "The depth setting"], correctIndex: 0, rationale: "Nyquist limit = PRF/2. Velocities exceeding this limit cause aliasing (wraparound). Increasing PRF, using a lower baseline, or switching to CW Doppler addresses aliasing.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-149", stem: "The 'Mercedes-Benz sign' on PSAX at the aortic valve level confirms:", options: ["A trileaflet (normal) aortic valve", "A bicuspid aortic valve", "A unicuspid aortic valve", "A quadricuspid aortic valve"], correctIndex: 0, rationale: "The three commissures of a normal trileaflet aortic valve create the Mercedes-Benz or inverted-Y pattern in diastole. Absence of one commissure line suggests bicuspid valve.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-150", stem: "The apical 3-chamber (A3C) view is equivalent to:", options: ["A parasternal long-axis view rotated to the apical window", "Subcostal four-chamber view", "Suprasternal notch view", "Parasternal short-axis view"], correctIndex: 0, rationale: "The A3C view shows the same structures as the PLAX (LV, LA, LVOT, aortic valve, mitral valve) but from the apex. It is useful when parasternal windows are poor.", difficulty: 2, category: "Adult Echocardiography", topic: "Standard Views" },
  { id: "cardecho-151", stem: "Spontaneous echo contrast ('smoke') in the left atrium suggests:", options: ["Blood stasis with increased thromboembolic risk, commonly seen in atrial fibrillation or mitral stenosis", "Normal blood flow", "Air in the left atrium", "Contrast agent injection"], correctIndex: 0, rationale: "Spontaneous echo contrast (SEC) results from red blood cell aggregation due to low-flow states. It is a marker of increased thromboembolic risk, commonly seen in AF, LA dilation, or MS.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-152", stem: "The Coanda effect in echocardiography describes:", options: ["An eccentric regurgitant jet that hugs the wall of the receiving chamber, making severity assessment by jet area unreliable", "Central jet trajectory", "Normal valve closure", "Acoustic shadowing"], correctIndex: 0, rationale: "The Coanda effect causes eccentric jets (e.g., from flail MV leaflet) to adhere to chamber walls. Wall-hugging jets appear smaller by area but may represent severe regurgitation, requiring quantitative methods.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-153", stem: "Left atrial volume index (LAVI) is measured using:", options: ["Biplane area-length or Simpson's method from A4C and A2C views, indexed to BSA", "M-mode LA diameter only", "Doppler-derived estimates", "3D only"], correctIndex: 0, rationale: "LAVI is measured using biplane method from A4C and A2C at end-systole (just before MV opening). Normal LAVI is <34 mL/m². Elevated LAVI indicates chronic diastolic dysfunction or volume overload.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-154", stem: "TAPSE (tricuspid annular plane systolic excursion) is measured by:", options: ["M-mode of the lateral tricuspid annulus in the A4C view, measuring total longitudinal excursion", "PW Doppler at the LVOT", "2D planimetry of the TV orifice", "CW Doppler across the pulmonary valve"], correctIndex: 0, rationale: "TAPSE measures the longitudinal displacement of the lateral tricuspid annulus toward the apex during systole. Normal ≥17 mm. TAPSE <17 mm suggests RV systolic dysfunction.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-155", stem: "RV fractional area change (FAC) is calculated from:", options: ["RV end-diastolic area minus end-systolic area divided by end-diastolic area in the A4C view", "LVOT VTI times heart rate", "TR jet velocity squared", "Mitral E/A ratio"], correctIndex: 0, rationale: "RV FAC = (EDA - ESA) / EDA × 100%. Normal is >35%. FAC <35% indicates RV systolic dysfunction. The RV is traced in the A4C view at end-diastole and end-systole.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-156", stem: "The RV S' velocity by tissue Doppler at the lateral tricuspid annulus assesses:", options: ["Right ventricular longitudinal systolic function", "Left ventricular diastolic function", "Pulmonary valve stenosis severity", "Mitral regurgitation severity"], correctIndex: 0, rationale: "RV S' (systolic velocity) by TDI at the lateral tricuspid annulus reflects RV longitudinal systolic function. Normal S' ≥9.5 cm/s. Reduced S' suggests RV dysfunction.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-157", stem: "The myocardial performance index (Tei index) combines:", options: ["Isovolumic contraction time plus isovolumic relaxation time divided by ejection time", "Stroke volume and heart rate", "Peak velocity and mean gradient", "E wave and A wave velocities"], correctIndex: 0, rationale: "Tei index = (IVCT + IVRT) / ET. It reflects global systolic and diastolic function. Normal LV Tei <0.40 (PW method) or <0.48 (TDI). Increased values indicate global dysfunction.", difficulty: 4, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-158", stem: "During TEE, the probe is advanced to approximately what distance from the incisors to reach the mid-esophageal position?", options: ["30-35 cm", "10-15 cm", "50-60 cm", "70-80 cm"], correctIndex: 0, rationale: "Mid-esophageal views are obtained with the probe at 30-35 cm from the incisors. Transgastric views require advancing to 40-45 cm. Upper esophageal views are at 20-25 cm.", difficulty: 2, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-159", stem: "The mid-esophageal commissural view at 60 degrees displays:", options: ["The mitral valve showing the A2 scallop and both commissures (P1-P3 junction and A1-A3 junction)", "Only the aortic valve", "The tricuspid valve only", "The descending aorta"], correctIndex: 0, rationale: "The ME commissural view at approximately 60° shows the mitral valve at the commissural level, displaying the A2 scallop flanked by the posteromedial and anterolateral commissures.", difficulty: 4, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-160", stem: "Acoustic shadowing from a heavily calcified structure on 2D echo appears as:", options: ["An echo-free area distal to the calcification where ultrasound cannot penetrate", "Increased brightness beyond the calcification", "Normal tissue appearance", "Color flow enhancement"], correctIndex: 0, rationale: "Acoustic shadowing occurs when a highly reflective/absorptive structure (calcification, prosthesis) blocks ultrasound transmission, creating a dark area (shadow) behind it. Limits visualization of structures behind the calcification.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-161", stem: "Side lobe artifacts in echocardiography can mimic:", options: ["Intracardiac masses or abnormal echoes within cardiac chambers", "Increased Doppler velocities", "Reduced frame rate", "Enhanced resolution"], correctIndex: 0, rationale: "Side lobes are low-intensity beams emitted at angles from the main beam. They can create artifactual echoes within anechoic chambers (e.g., mimicking LV thrombus or vegetations). Changing imaging windows helps distinguish artifact from pathology.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-162", stem: "Mirror image artifacts in echocardiography commonly occur at:", options: ["Highly reflective interfaces such as the pericardium or diaphragm, creating a duplicate image", "Low-gain settings", "Shallow depth imaging", "High-frequency transducers"], correctIndex: 0, rationale: "Mirror image artifact: a strong reflector (pericardium, diaphragm, pleura) acts as a mirror, creating a duplicate structure on the opposite side. Common in the descending aorta on TEE.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-163", stem: "The Lambl's excrescence seen on the aortic valve is:", options: ["A thin, filamentous strand on the valve closure line that is a normal or age-related finding", "A large vegetation indicating endocarditis", "A tumor requiring surgery", "An air embolism"], correctIndex: 0, rationale: "Lambl's excrescences are thin, filamentous strands on valve closure lines, considered normal variants or degenerative changes. Distinguished from vegetations by their thin, thread-like appearance and typical location.", difficulty: 3, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-164", stem: "The moderator band is a normal structure seen in:", options: ["The right ventricle, extending from the interventricular septum to the RV free wall", "The left atrium", "The left ventricle only", "The aortic root"], correctIndex: 0, rationale: "The moderator band is a muscular band in the RV carrying the right bundle branch. It should not be confused with a thrombus or mass. It extends from the septum to the RV free wall near the apex.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-165", stem: "The Eustachian valve is a normal structure located at:", options: ["The junction of the IVC and right atrium", "The mitral valve annulus", "The aortic root", "The left atrial appendage"], correctIndex: 0, rationale: "The Eustachian valve is a remnant of the embryonic right valve of the sinus venosus, located at the IVC-RA junction. It can be prominent and should not be mistaken for a mass or vegetation.", difficulty: 1, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-166", stem: "The Chiari network is:", options: ["A fenestrated, mobile, web-like structure in the right atrium that is a normal embryological remnant", "An abnormal mass requiring excision", "A thrombus in the left atrium", "A prosthetic valve complication"], correctIndex: 0, rationale: "The Chiari network is a remnant of the right valve of the sinus venosus. It appears as a thin, mobile, fenestrated membrane in the RA, typically attached near the Eustachian valve and coronary sinus.", difficulty: 2, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-167", stem: "Lipomatous hypertrophy of the interatrial septum on echo shows:", options: ["Thickened IAS (>2 cm) with sparing of the fossa ovalis, creating a dumbbell shape", "Thinned IAS", "ASD at the fossa ovalis", "Normal IAS thickness throughout"], correctIndex: 0, rationale: "Lipomatous hypertrophy: fatty infiltration of the IAS causing thickening >2 cm, characteristically sparing the fossa ovalis (creating a dumbbell or hourglass shape). Usually benign, associated with obesity and aging.", difficulty: 4, category: "Adult Echocardiography", topic: "2D Imaging" },
  { id: "cardecho-168", stem: "Proper TEE probe disinfection after each use requires:", options: ["High-level disinfection following manufacturer and infection control guidelines", "Rinsing with tap water only", "Wiping with a dry cloth", "No disinfection necessary"], correctIndex: 0, rationale: "TEE probes require high-level disinfection (HLD) between patients using approved agents (e.g., glutaraldehyde, ortho-phthalaldehyde, or automated reprocessing systems) per manufacturer and institutional protocols.", difficulty: 1, category: "Adult Echocardiography", topic: "TEE Views and Indications" },
  { id: "cardecho-169", stem: "Twist and untwist mechanics of the LV assessed by speckle tracking represent:", options: ["Rotational deformation where the apex rotates counterclockwise and base clockwise during systole", "Pure radial thickening", "Valve opening mechanics", "Atrial contraction patterns"], correctIndex: 0, rationale: "LV twist (torsion) results from obliquely oriented myocardial fibers. During systole, the apex rotates counterclockwise and the base clockwise (viewed from apex). Untwisting in early diastole generates suction for filling.", difficulty: 5, category: "Adult Echocardiography", topic: "Strain Imaging" },
];
